def retry(func=None, max_attempts=3):
    def decorator(f):
        def wrapper(*args, **kwargs):
            for i in range(max_attempts):
                try:
                    return f(*args, **kwargs)
                except Exception:
                    if i == max_attempts:
                        raise
            return None
        wrapper.__name__ = f.__name__
        return wrapper
    if func is not None:
        return decorator(func)
    return decorator

