def memoize(func):
    cache = {}
    def wrapper(*args, **kwargs):
        key = args
        if key in cache:
            return cache[key]
        result = func(*args, **kwargs)
        cache[key] = result
        return result
    wrapper.__name__ = func.__name__
    return wrapper

