def has_cycle(graph):
    visited = set()
    def dfs(node):
        if node in visited:
            return True
        visited.add(node)
        for neighbor in graph.get(node, []):
            if dfs(neighbor):
                return True
        return False

    for node in graph:
        if node not in visited:
            if dfs(node):
                return True
    return False

